class Solution(object):
    def minimumSumSubarray(self, nums, l, r):
        n = len(nums)
        best = float('inf')
        for length in range(l, r + 1):
            for i in range(n - length + 1):
                s = sum(nums[i:i + length])
                if s > 0:
                    best = min(best, s)
        return best if best < float('inf') else -1
